    <!-- Lucide Icons -->
    <script src="https://cdn.jsdelivr.net/npm/swiper@11/swiper-bundle.min.js"></script>
    <script src="https://unpkg.com/lucide@latest"></script>
    <script>
        // Initialize Lucide Icons
        lucide.createIcons();


        // Types Slider (Swiper)
        const typesSwiper = new Swiper(".types-swiper", {
            watchOverflow: false,
            slidesPerView: 1,
            spaceBetween: 24,
            navigation: {
                nextEl: ".types-next",
                prevEl: ".types-prev",
            },
            breakpoints: {
                640: { slidesPerView: 2 },
                1024: { slidesPerView: 4 },
            },
        });


        // Slider Navigation Logic
        const sliderWrap = document.querySelector(".venues-slider-wrap");
        const prevBtn = document.querySelector(".control-btn.prev");
        const nextBtn = document.querySelector(".control-btn.next");


        if (sliderWrap && prevBtn && nextBtn) {
            const updateButtons = () => {
                const scrollLeft = sliderWrap.scrollLeft;
                const maxScrollLeft = sliderWrap.scrollWidth - sliderWrap.clientWidth;


                prevBtn.disabled = scrollLeft <= 0;
                nextBtn.disabled = scrollLeft >= maxScrollLeft - 2; // Tolerance for fractional pixels
            };


            // Initialize state
            updateButtons();


            // Listen for scroll events
            sliderWrap.addEventListener("scroll", updateButtons);


            nextBtn.addEventListener("click", () => {
                sliderWrap.scrollBy({ left: 500, behavior: "smooth" });
            });


            prevBtn.addEventListener("click", () => {
                sliderWrap.scrollBy({ left: -500, behavior: "smooth" });
            });
        }


        // Mobile Menu Toggle
        const menuToggle = document.getElementById("menuToggle");
        const navLinks = document.querySelector(".nav-links");


        if (menuToggle && navLinks) {
            menuToggle.addEventListener("click", () => {
                navLinks.classList.toggle("active");
                menuToggle.classList.toggle("active");
            });
        }


        // FAQ Accordion
        const faqItems = document.querySelectorAll(".faq-item");
        faqItems.forEach((item) => {
            const question = item.querySelector(".faq-question");
            question.addEventListener("click", () => {
                const isActive = item.classList.contains("active");
                // Close all
                faqItems.forEach((i) => i.classList.remove("active"));
                // Open clicked if it wasn't active
                if (!isActive) item.classList.add("active");
            });
        });
    </script>

